#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <omp.h>
#include <stdint.h>

#define OMP_CHECK(x) do { \
    int err = (x); \
    if (err != 0) { \
        printf("OpenMP runtime error %s:%d: %d\n", __FILE__, __LINE__, err); \
        exit(1); \
    } \
} while (0)

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
void conv1d_kernel(const T * __restrict__ in,
                   T * __restrict__ out,
                   const T * __restrict__ mask,
                   const int input_width,
                   const int mask_width,
                   const int bs)
{
  const int grids = input_width / bs;
  #pragma omp target teams is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  {
    int blockIdx_x = omp_get_team_num();
    #pragma omp parallel num_threads(bs)
    {
      int threadIdx_x = omp_get_thread_num();
      int i = threadIdx_x + blockIdx_x * bs;
      T s = 0;
      int start = i - mask_width / 2;
      for (int j = 0; j < mask_width; j++) {
        if (0 <= start + j && start + j < input_width) {
          s += in[start + j] * mask[j];
        }
      }
      out[i] = s;
    }
  }
}

template<typename T>
void conv1d_tiled_kernel(const T * __restrict__ in,
                         T * __restrict__ out,
                         const T * __restrict__ mask,
                         const int input_width,
                         const int mask_width,
                         const int bs)
{
  const int grids = input_width / bs;
  #pragma omp target teams is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  {
    T tile[MAX_BLOCK_SIZE + MAX_MASK_WIDTH - 1];
    int blockIdx_x = omp_get_team_num();
    int n = mask_width / 2;

    #pragma omp parallel num_threads(bs)
    {
      int threadIdx_x = omp_get_thread_num();
      int i = threadIdx_x + blockIdx_x * bs;

      int halo_left = (blockIdx_x - 1) * bs + threadIdx_x;
      if (threadIdx_x >= bs - n)
        tile[threadIdx_x - (bs - n)] = halo_left < 0 ? 0 : in[halo_left];

      tile[n + threadIdx_x] = in[blockIdx_x * bs + threadIdx_x];

      int halo_right = (blockIdx_x + 1) * bs + threadIdx_x;
      if (threadIdx_x < n)
        tile[threadIdx_x + bs + n] = halo_right >= input_width ? 0 : in[halo_right];

      #pragma omp barrier

      T s = 0;
      for (int j = 0; j < mask_width; j++)
        s += tile[threadIdx_x + j] * mask[j];

      out[i] = s;
    }
  }
}

template<typename T>
void conv1d_tiled_caching_kernel(const T * __restrict__ in,
                                 T * __restrict__ out,
                                 const T * __restrict__ mask,
                                 const int input_width,
                                 const int mask_width,
                                 const int bs)
{
  const int grids = input_width / bs;
  #pragma omp target teams is_device_ptr(in, out, mask) num_teams(grids) thread_limit(bs)
  {
    T tile[MAX_BLOCK_SIZE];
    int blockIdx_x = omp_get_team_num();

    #pragma omp parallel num_threads(bs)
    {
      int threadIdx_x = omp_get_thread_num();
      int i = threadIdx_x + blockIdx_x * bs;
      tile[threadIdx_x] = in[i];

      #pragma omp barrier

      int this_tile_start = blockIdx_x * bs;
      int next_tile_start = (blockIdx_x + 1) * bs;
      int start = i - (mask_width / 2);
      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        int in_index = start + j;
        if (in_index >= 0 && input_width > in_index) {
          if (this_tile_start <= in_index && next_tile_start > in_index) {
            s += tile[threadIdx_x + j - (mask_width / 2)] * mask[j];
          } else {
            s += in[in_index] * mask[j];
          }
        }
      }
      out[i] = s;
    }
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; input_width > i; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (0 <= start + j && input_width > start + j) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs((double)(s - d_out[i])) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = (size_t)input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes);
  b = (T *)malloc(size_bytes);

  T h_mask[MAX_MASK_WIDTH];

  for (int i = 0; MAX_MASK_WIDTH > i; i++) h_mask[i] = 1;

  srand(123);
  for (int i = 0; input_width > i; i++) {
    a[i] = (T)(rand() % 256);
  }

  int dev = omp_get_default_device();
  int host = omp_get_initial_device();

  T *d_a = (T *)omp_target_alloc(size_bytes, dev);
  T *d_b = (T *)omp_target_alloc(size_bytes, dev);
  T *d_mask = (T *)omp_target_alloc(MAX_MASK_WIDTH * sizeof(T), dev);

  if (!d_a || !d_b || !d_mask) {
    printf("OpenMP target allocation failed\n");
    exit(1);
  }

  OMP_CHECK(omp_target_memcpy(d_a, a, size_bytes, 0, 0, dev, host));
  OMP_CHECK(omp_target_memcpy(d_mask, h_mask, (size_t)mask_width * sizeof(T), 0, 0, dev, host));

  for (int bs = 64; MAX_BLOCK_SIZE >= bs; bs *= 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_kernel<T>(d_a, d_b, d_mask, input_width, mask_width, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    OMP_CHECK(omp_target_memcpy(b, d_b, size_bytes, 0, 0, host, dev));
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; MAX_BLOCK_SIZE >= bs; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_kernel<T>(d_a, d_b, d_mask, input_width, mask_width, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    OMP_CHECK(omp_target_memcpy(b, d_b, size_bytes, 0, 0, host, dev));
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; MAX_BLOCK_SIZE >= bs; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; repeat > i; i++) {
      conv1d_tiled_caching_kernel<T>(d_a, d_b, d_mask, input_width, mask_width, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    OMP_CHECK(omp_target_memcpy(b, d_b, size_bytes, 0, 0, host, dev));
    reference(a, b, h_mask, input_width, mask_width);
  }

  free(a);
  free(b);
  omp_target_free(d_a, dev);
  omp_target_free(d_b, dev);
  omp_target_free(d_mask, dev);
}

int main(int argc, char* argv[]) {
  if (3 != argc) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);
  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width);

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
